                .description
                .as_deref()
                .and_then(|text| scan_tool_definition("description", text))
            {
                emit_rejection(server, &tool.name, &hit.code);
                return None;
            }
            if let Some(hit) = tool
                .title
                .as_deref()
                .and_then(|text| scan_tool_definition("title", text))
            {
                emit_rejection(server, &tool.name, &hit.code);
                return None;
            }
            Some(tool)
        }).collect

function:src/openhuman/mcp_client/sanitize.rs:input
        .chars()
        .filter(|ch| {
            if *ch == '\n' || *ch == '\t' {
                return true;
            }
            // Drop ASCII C0 and DEL.
            let code = *ch as u32;
            !(code <= 0x1f || code == 0x7f)
        }).collect
